namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }

    public int OriginalSentenceCount { get; set; }

    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "it",
        "this", "that", "these", "those", "be", "been", "being", "have",
        "has", "had", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "shall", "can", "not", "no", "so",
        "if", "then", "than", "too", "very", "just", "about", "above",
        "after", "again", "all", "also", "am", "as", "because", "before",
        "between", "both", "during", "each", "he", "she", "we", "they",
        "i", "me", "my", "your", "its", "his", "her", "our", "their",
        "what", "which", "who", "whom", "how", "when", "where", "why"
    };

    /// <summary>
    /// Produces an extractive summary by selecting the highest-scoring sentences
    /// based on word-frequency relevance.
    /// </summary>
    public (string Summary, int OriginalCount, int SummaryCount) Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count <= maxSentences)
        {
            return (text.Trim(), sentences.Count, sentences.Count);
        }

        var wordScores = BuildWordFrequencyMap(sentences);
        var scored = ScoreSentences(sentences, wordScores);

        var topSentences = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Sentence.Trim());

        var summary = string.Join(" ", topSentences);
        return (summary, sentences.Count, maxSentences);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceSplitter()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, double> BuildWordFrequencyMap(List<string> sentences)
    {
        var frequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word))
                {
                    frequency[word] = frequency.GetValueOrDefault(word) + 1;
                }
            }
        }

        if (frequency.Count == 0)
            return [];

        var maxFreq = frequency.Values.Max();
        return frequency.ToDictionary(
            kvp => kvp.Key,
            kvp => (double)kvp.Value / maxFreq,
            StringComparer.OrdinalIgnoreCase);
    }

    private static List<(string Sentence, int Index, double Score)> ScoreSentences(
        List<string> sentences, Dictionary<string, double> wordScores)
    {
        return sentences
            .Select((sentence, index) =>
            {
                var words = ExtractWords(sentence);
                var score = words
                    .Where(w => wordScores.ContainsKey(w))
                    .Sum(w => wordScores[w]);

                // Normalize by word count to avoid bias toward long sentences
                var normalizedScore = words.Count > 0 ? score / words.Count : 0;
                return (sentence, index, normalizedScore);
            })
            .ToList();
    }

    private static List<string> ExtractWords(string text)
    {
        return WordExtractor()
            .Matches(text)
            .Select(m => m.Value)
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordExtractor();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizer;

    public SummarizeController(DocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var (summary, originalCount, summaryCount) = _summarizer.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

